function load() {
	let starPath = getStarPath();
	//console.log(starPath);
	document.getElementById('star').setAttribute('d',starPath);
}


function getStarPath(number) {
	const length = 1000;
	let path = '';
	let x = 0, y = 0;
	const sides = 12;
	const divisions = 3;

	const mainAngle = Math.TAU / sides;

	let angle = mainAngle/2;

	const internalAngle = mainAngle / divisions;

	console.log(mainAngle, internalAngle);

	const points = sides * divisions;

	for (let i=0; i < sides; i++)
	{
		angle += 5*mainAngle; <!--  i* -->

		const p = new PolarPoint(angle, length).toPoint();

		x = Math.round(p.x);
		y = Math.round(p.y);
		console.log(i,Maths.radiansToDegrees(angle),x,y);

		path  += (i===0) ? `M ${x} ${y} ` : `L ${x} ${y} `;
	}

	return `${path} Z`;
}
